1	//! R2 — rule rendering: the whole rule block, byte-identical to the echo.
2	//!
3	//! Every layout decision is oracle-pinned (see workspace/BEHAVIOR.md "Rule
4	//! blocks" for probe provenance). Shape summary:
5	//!
6	//! ```text
7	//! rule (modulo E) Name[color=#abcdef, no_derivcheck, issapicrule,
8	//!                      role='r']:
9	//!    [ Prem( x ), !Persistent( y )[+, no_precomp] ]
10	//!   --[ Act( x ) ]->
11	//!    [ Concl( x ) ]
12	//!
13	//!   // loop breakers: [0,1]
14	//!   /* has exactly the trivial AC variant */
15	//! ```
16	//!
17	//! * body = `nest 3 (sep [prems, nest (-1) arrow, concls])` — one line when
18	//!   it fits, otherwise premises/conclusions at indent 3 and the arrow row at
19	//!   indent 2;
20	//! * each bracket group = `sep ["[", fsep facts, "]"]` (`[ ]` when empty);
21	//!   the empty-action arrow is the literal `-->`;
22	//! * a fact = `sep [name<>"(" <+> fsep args, ")"]` (`Name( )` when nullary)
23	//!   with the annotation suffix attached after the `)`;
24	//! * the trailing comment is either the trivial-variant one-liner or the
25	//!   `/* rule (modulo AC) … variants (modulo AC) … */` block with numbered
26	//!   substitution groups: number right-aligned to the widest index, each
27	//!   substitution `lhs $$ nest 6 ("= " <> rhs)` — the HughesPJ overlap pads
28	//!   a short lhs to column 6 and pushes `= rhs` to its own line otherwise.
29	
30	use crate::ast::{AcVariants, Fact, FactAnnotation, Rule, RuleAttr, Term};
31	use crate::doc::{
32	    above_op, above_plus, beside_op, beside_space, char, fsep, nest, punctuate,
33	    render_with, sep, text, vcat, Doc,
34	};
35	use crate::term::{self, RIBBON, WIDTH};
36	
37	/// One fact: `Name( arg, … )`, persistent prefixed with `!`, annotations
38	/// attached after the closing paren.
39	pub fn render_fact(f: &Fact) -> String {
40	    render_with(WIDTH, RIBBON, &fact_doc(f))
41	}
42	
43	/// One whole rule block: header, body, blank line, loop-breaker annotation,
44	/// and the AC-variants comment (`None` → the trivial-variant one-liner).
45	pub fn render(rule: &Rule, variants: Option<&AcVariants>) -> String {
46	    render_with(WIDTH, RIBBON, &block_doc(rule, variants))
47	}
48	
49	fn block_doc(rule: &Rule, variants: Option<&AcVariants>) -> Doc {
50	    let mut d = core_doc(rule);
51	    // `$+$` below the blank line: `$$` overlap would otherwise pull the
52	    // nested comment line up onto it.
53	    d = above_plus(d, text(""));
54	    if let Some(lb) = breaker_doc(&rule.loop_breakers) {
55	        d = above_plus(d, nest(2, &lb));
56	    }
57	    above_plus(d, nest(2, &comment_doc(variants)))
58	}
59	
60	/// Header + body (shared by the toplevel block and the AC rule re-rendered
61	/// inside the variants comment).
62	fn core_doc(rule: &Rule) -> Doc {
63	    above_op(header_doc(rule), nest(3, &body_doc(rule)))
64	}
65	
66	// ── header ──────────────────────────────────────────────────────────────────
67	
68	/// `rule (modulo E) Name:`, with the rendered attribute list in `[…]` before
69	/// the colon; attributes fill-wrap aligned after the `[`
70	/// (target:issue713, probe:p_rattr).
71	fn header_doc(rule: &Rule) -> Doc {
72	    let mut head = String::from("rule ");
73	    if let Some(m) = &rule.modulo {
74	        head.push_str(&format!("(modulo {m}) "));
75	    }
76	    head.push_str(&rule.name);
77	    let attrs = attr_items(&rule.attributes);
78	    if attrs.is_empty() {
79	        text(&format!("{head}:"))
80	    } else {
81	        beside_op(
82	            beside_op(
83	                text(&format!("{head}[")),
84	                fsep(punctuate(
85	                    &char(','),
86	                    attrs.iter().map(|a| text(a)).collect(),
87	                )),
88	            ),
89	            text("]:"),
90	        )
91	    }
92	}
93	
94	/// Canonical attribute list: color, no_derivcheck, issapicrule, role — the
95	/// last color/role declaration wins; `process=…` and external attributes are
96	/// dropped (probe:p_rattr, target:issue713).
97	fn attr_items(attrs: &[RuleAttr]) -> Vec<String> {
98	    let mut color = None;
99	    let mut no_derivcheck = false;
100	    let mut issapicrule = false;
101	    let mut role = None;
102	    for a in attrs {
103	        match a {
104	            RuleAttr::Color(c) => color = Some(c.clone()),
105	            RuleAttr::NoDerivCheck => no_derivcheck = true,
106	            RuleAttr::IsSapicRule => issapicrule = true,
107	            RuleAttr::Role(r) => role = Some(r.clone()),
108	            RuleAttr::Process(_) | RuleAttr::External(..) => {}
109	        }
110	    }
111	    let mut items = Vec::new();
112	    if let Some(c) = color {
113	        items.push(format!("color=#{c}"));
114	    }
115	    if no_derivcheck {
116	        items.push("no_derivcheck".into());
117	    }
118	    if issapicrule {
119	        items.push("issapicrule".into());
120	    }
121	    if let Some(r) = role {
122	        items.push(format!("role='{r}'"));
123	    }
124	    items
125	}
126	
127	// ── body ────────────────────────────────────────────────────────────────────
128	
129	/// `sep [prems, nest (-1) arrow, concls]` under the rule's nest 3: one line
130	/// `[ … ] --[ … ]-> [ … ]` when it fits, otherwise three rows with the arrow
131	/// out-dented one column (targets cav13/NSLPK3, probe:t_wide).
132	fn body_doc(rule: &Rule) -> Doc {
133	    sep(vec![
134	        fact_list_doc(&rule.premises),
135	        nest(-1, &arrow_doc(&rule.actions)),
136	        fact_list_doc(&rule.conclusions),
137	    ])
138	}
139	
140	/// `-->` when there are no actions, otherwise the `--[ … ]->` bracket group
141	/// (probe:p_arr1 rule AR pins the arrow to the SAME nested-sep construction
142	/// as the premise/conclusion lists: actions stay beside `--[` while `]->`
143	/// drops alone).
144	fn arrow_doc(actions: &[Fact]) -> Doc {
145	    if actions.is_empty() {
146	        text("-->")
147	    } else {
148	        bracket_group("--[", actions, "]->")
149	    }
150	}
151	
152	fn fact_list_doc(facts: &[Fact]) -> Doc {
153	    bracket_group("[", facts, "]")
154	}
155	
156	/// `sep [sep [open, fsep facts], close]` — a graded three-way layout
157	/// (probe:p_arr1; targets mesh ProvisionerWaitingUser vs DeviceWaitingUser,
158	/// NSLPK3 R_1/I_2, Tutorial Serv_1):
159	///   * everything on one line when `open facts close` fits (`[ f1, f2 ]`,
160	///     kept at exactly ribbon width — p_arr1 rule PR at 73);
161	///   * otherwise the closing bracket drops to the group's column; the
162	///     opening bracket keeps ALL the facts beside it iff they fit on that
163	///     line as a unit (mesh DeviceWaitingUser at exactly 73);
164	///   * otherwise the opening bracket is alone too and the facts fill-wrap
165	///     at the group's column between the brackets (NSLPK3 R_1: three facts
166	///     share a fill line; Serv_1: `--[` alone although the first action
167	///     would fit beside it).
168	fn bracket_group(open: &str, facts: &[Fact], close: &str) -> Doc {
169	    if facts.is_empty() {
170	        return sep(vec![text(open), text(close)]);
171	    }
172	    sep(vec![
173	        sep(vec![
174	            text(open),
175	            fsep(punctuate(&char(','), facts.iter().map(fact_doc).collect())),
176	        ]),
177	        text(close),
178	    ])
179	}
180	
181	// ── facts ───────────────────────────────────────────────────────────────────
182	
183	/// `Name( a, b )` — args fill-wrap aligned after `Name( `, the closing paren
184	/// drops to the fact's own column when the args are multi-line
185	/// (probe:t_wide); `Name( )` when nullary (target:mesh); `!` prefix for
186	/// persistent facts; annotation suffix attached directly after the paren.
187	fn fact_doc(f: &Fact) -> Doc {
188	    let head = format!("{}{}(", if f.persistent { "!" } else { "" }, f.name);
189	    let core = if f.args.is_empty() {
190	        sep(vec![text(&head), char(')')])
191	    } else {
192	        sep(vec![
193	            beside_space(
194	                text(&head),
195	                fsep(punctuate(
196	                    &char(','),
197	                    f.args.iter().map(term::doc).collect(),
198	                )),
199	            ),
200	            char(')'),
201	        ])
202	    };
203	    match annotation_suffix(&f.annotations) {
204	        Some(s) => beside_op(core, text(&s)),
205	        None => core,
206	    }
207	}
208	
209	/// `[+, -, no_precomp]` in canonical order regardless of source order
210	/// (probe:p_fann `[no_precomp,+]` → `[+, no_precomp]`; target:seqdfsneeded
211	/// `[no_precomp,-]` → `[-, no_precomp]`).
212	fn annotation_suffix(annotations: &[FactAnnotation]) -> Option<String> {
213	    if annotations.is_empty() {
214	        return None;
215	    }
216	    let mut sorted: Vec<FactAnnotation> = annotations.to_vec();
217	    sorted.sort();
218	    sorted.dedup();
219	    let spellings: Vec<&str> = sorted
220	        .iter()
221	        .map(|a| match a {
222	            FactAnnotation::SolveFirst => "+",
223	            FactAnnotation::SolveLast => "-",
224	            FactAnnotation::NoSources => "no_precomp",
225	        })
226	        .collect();
227	    Some(format!("[{}]", spellings.join(", ")))
228	}
229	
230	// ── loop breakers ───────────────────────────────────────────────────────────
231	
232	/// `// loop breaker: [0]` / `// loop breakers: [0,1]` — plural iff several,
233	/// indices comma-separated without spaces (probes c_loop, p_lb2).
234	fn breaker_doc(indices: &[usize]) -> Option<Doc> {
235	    if indices.is_empty() {
236	        return None;
237	    }
238	    let list = indices
239	        .iter()
240	        .map(|i| i.to_string())
241	        .collect::<Vec<_>>()
242	        .join(",");
243	    let noun = if indices.len() == 1 {
244	        "loop breaker"
245	    } else {
246	        "loop breakers"
247	    };
248	    Some(text(&format!("// {noun}: [{list}]")))
249	}
250	
251	// ── the AC-variants comment ─────────────────────────────────────────────────
252	
253	/// `None` → the trivial one-liner; otherwise the comment block re-rendering
254	/// the AC rule, its numbered substitution groups, and its loop-breaker line
255	/// (probes p_var1, p_lbvar; targets cav13/Joux/CH07/mesh).
256	fn comment_doc(variants: Option<&AcVariants>) -> Doc {
257	    let Some(v) = variants else {
258	        return text("/* has exactly the trivial AC variant */");
259	    };
260	    let mut d = above_op(text("/*"), core_doc(&v.ac_rule));
261	    if !v.substitutions.is_empty() {
262	        d = above_op(d, nest(2, &substitutions_doc(&v.substitutions)));
263	    }
264	    if let Some(lb) = breaker_doc(&v.ac_rule.loop_breakers) {
265	        d = above_op(d, nest(2, &lb));
266	    }
267	    above_op(d, text("*/"))
268	}
269	
270	/// `variants (modulo AC)` and the numbered groups, separated by lines of
271	/// bare indent (four spaces at the observed nesting — probe:p_var1 byte
272	/// check); numbers right-aligned to the widest index (`  1.` … `160.` —
273	/// targets cav13 (1 digit), CH07 (2), Joux (3)).
274	fn substitutions_doc(groups: &[Vec<(Term, Term)>]) -> Doc {
275	    let width = groups.len().to_string().len();
276	    let mut rows = vec![text("variants (modulo AC)")];
277	    for (i, group) in groups.iter().enumerate() {
278	        if i > 0 {
279	            rows.push(text(""));
280	        }
281	        let prefix = format!("{:>width$}. ", i + 1);
282	        rows.push(beside_op(
283	            text(&prefix),
284	            vcat(group.iter().map(|(l, r)| substitution_doc(l, r)).collect()),
285	        ));
286	    }
287	    vcat(rows)
288	}
289	
290	/// One substitution: `lhs $$ nest 6 ("= " <> rhs)` — the overlap pads a
291	/// short lhs to column 6 (`~lv2  = ~lv2.4`) and drops `= rhs` to its own
292	/// line at column 6 when the lhs is 6 columns or wider (probe:p_var1
293	/// `~longvariablenameone`); the rhs is a full R1 term with its own wrapping
294	/// (target:mesh multi-line substitution values).
295	fn substitution_doc(lhs: &Term, rhs: &Term) -> Doc {
296	    above_op(
297	        term::doc(lhs),
298	        nest(6, &beside_op(text("= "), term::doc(rhs))),
299	    )
300	}
