101	// ── functions line ──────────────────────────────────────────────────────────
102	
103	fn decl(name: &str, arity: usize, private: bool, destructor: bool) -> FunctionDecl {
104	    FunctionDecl {
105	        name: name.into(),
106	        arity,
107	        private,
108	        destructor,
109	    }
110	}
111	
112	/// `name/arity` + attribute suffix (probe:f_attrs): `private` implies a
113	/// role keyword is shown too; a public destructor shows `[destructor]` alone;
114	/// a public constructor shows nothing.
115	fn function_item(d: &FunctionDecl) -> String {
116	    let mut s = format!("{}/{}", d.name, d.arity);
117	    if d.private || d.destructor {
118	        let mut attrs: Vec<&str> = Vec::new();
119	        if d.private {
120	            attrs.push("private");
121	        }
122	        attrs.push(if d.destructor { "destructor" } else { "constructor" });
123	        s.push('[');
124	        s.push_str(&attrs.join(","));
125	        s.push(']');
126	    }
127	    s
128	}
129	
130	/// Base + builtin-expansion + user function symbols, deduped and byte-sorted.
131	/// Sorting the full item text equals sorting by name (`/` orders below every
132	/// identifier character), matching probe:f_sort.
133	fn merged_function_items(sig: &Signature) -> Vec<String> {
134	    let mut decls: Vec<FunctionDecl> = base_functions(&sig.builtins);
135	    for b in &sig.builtins {
136	        decls.extend(builtin_functions(b));
137	    }
138	    decls.extend(sig.functions.iter().cloned());
139	    let mut items: Vec<String> = decls.iter().map(function_item).collect();
140	    items.sort();
141	    items.dedup();
142	    items
143	}
144	
145	/// Always-present pairing symbols; `dest-pairing` flips the projections to
146	/// destructors (probe:b_none, probe:b_dest-pairing).
147	fn base_functions(declared: &[String]) -> Vec<FunctionDecl> {
148	    let dest = declared.iter().any(|b| b == "dest-pairing");
149	    vec![
150	        decl("fst", 1, false, dest),
151	        decl("pair", 2, false, false),
152	        decl("snd", 1, false, dest),
153	    ]
154	}
