163	            decl("aenc", 2, false, false),
164	            decl("pk", 1, false, false),
165	        ],
166	        "signing" | "dest-signing" => vec![
167	            decl("pk", 1, false, false),
168	            decl("sign", 2, false, false),
169	            decl("true", 0, false, false),
170	            decl("verify", 3, false, name.starts_with("dest-")),
171	        ],
172	        "symmetric-encryption" | "dest-symmetric-encryption" => vec![
173	            decl("sdec", 2, false, name.starts_with("dest-")),
174	            decl("senc", 2, false, false),
175	        ],
176	        "revealing-signing" => vec![
177	            decl("getMessage", 1, false, false),
178	            decl("pk", 1, false, false),
179	            decl("revealSign", 2, false, false),
180	            decl("revealVerify", 3, false, false),
181	            decl("true", 0, false, false),
182	        ],
