193	// ── equations block ─────────────────────────────────────────────────────────
194	
195	/// `sep (header : map (nest 4) (punctuate ',' eqs))`: one line when it fits,
196	/// otherwise header alone and one equation per line at indent 4
197	/// (probe:e_mid, probe:e_conv, target:Tutorial).
198	fn equations_doc(sig: &Signature) -> Doc {
199	    let header = if sig.convergent {
200	        "equations [convergent]:"
201	    } else {
202	        "equations:"
203	    };
204	    let eqs = merged_equations(sig);
205	    let mut elems = vec![text(header)];
206	    for d in punctuate(&char(','), eqs.iter().map(equation_doc).collect()) {
207	        elems.push(nest(4, &d));
208	    }
209	    sep(elems)
210	}
211	
212	/// `sep [lhs, nest (-2) ("= " <> rhs)]`: one line `lhs = rhs`; an overlong
213	/// equation drops `= rhs` to (equation indent − 2) (probe:e_long).
214	fn equation_doc(eq: &Equation) -> Doc {
215	    sep(vec![
216	        term::doc(&eq.lhs),
217	        nest(-2, &beside_op(text("= "), term::doc(&eq.rhs))),
218	    ])
219	}
220	
221	/// One-line text of an equation — the exact-dedup key (probe:e_dup pins
222	/// exact-dedup; probe:e_adedup pins that alpha-variants are kept).
223	fn equation_key(eq: &Equation) -> String {
224	    render_with(isize::MAX / 2, isize::MAX / 2, &equation_doc(eq))
225	}
226	
227	/// Base + builtin-expansion + user equations, deduped exactly and sorted by
228	/// the structural (lhs, rhs) order — see [`equation_cmp`]. The sort is
229	/// independent of declaration order (probes p_eqA/p_eqB, p_eqF/p_eqF2) and is
230	/// NOT byte order of the rendered text (target:contract checkpcs pair,
231	/// target:mesh get_b1/get_b2 groups, probes p_eqC/p_eqC2).
232	fn merged_equations(sig: &Signature) -> Vec<Equation> {
233	    let mut eqs = base_equations();
234	    for b in &sig.builtins {
235	        eqs.extend(builtin_equations(b));
236	    }
237	    eqs.extend(sig.equations.iter().cloned());
238	    let mut keyed: Vec<(String, Equation)> =
239	        eqs.into_iter().map(|e| (equation_key(&e), e)).collect();
240	    keyed.sort_by(|a, b| equation_cmp(&a.1, &b.1));
241	    keyed.dedup_by(|a, b| a.0 == b.0);
242	    keyed.into_iter().map(|(_, e)| e).collect()
243	}
244	
245	// ── equation ordering (structural term order) ───────────────────────────────
246	
247	/// Equations compare lexicographically on (lhs, rhs): rhs participates and
248	/// breaks lhs ties (probes p_eqF/p_eqF2 — identical lhs, `= x` before `= y`
249	/// regardless of declaration order).
250	fn equation_cmp(a: &Equation, b: &Equation) -> Ordering {
251	    term_cmp(&a.lhs, &b.lhs).then_with(|| term_cmp(&a.rhs, &b.rhs))
252	}
253	
254	/// A term as the comparison model sees it: either a real AST node or the
255	/// tail of a tuple (tuples compare as RIGHT-NESTED binary `pair`
256	/// applications — probe:p_eqI: `<x, zz>` sorts before `<x, b, c>` because
257	/// the binary view compares `zz` (a variable) against `pair(b, c)`; the
258	/// flattened elementwise view would order the other way).
259	#[derive(Clone, Copy)]
260	enum CmpView<'a> {
261	    Node(&'a Term),
262	    PairTail(&'a [Term]),
263	}
264	
265	/// Structural term order pinned by the equations block (probes p_eqA–p_eqI,
266	/// targets contract/mesh):
267	///   * variables sort below ALL applications, whatever the names
268	///     (p_eqC/p_eqC2: `zzz` before nullary `a0`; contract: `xpk` before
269	///     `pk(xsk)`; mesh: `cnf` before `aes_cmac(…)`);
270	///   * variable vs variable: name bytes, then index (p_eqD byte order not
271	///     shortlex: `azz` < `b`; p_eqH: `x` < `x.1`);
272	///   * application vs application: head name bytes FIRST (p_eqG refutes
273	///     arity-first: `pair` < `z1` despite arity 2 vs 1), then arguments
274	///     left-to-right (contract checkpcs decided at argument 2);
275	///   * tuples take the head name `pair` (p_eqE: `g(…)` < `<x, y>`; p_eqG:
276	///     `<x, y>` < `z1(…)`) and right-nested binary arguments (p_eqI).
277	/// Classes that cannot appear in an equations block (literals, exp/AC
278	/// operators, diff, pattern-match) are UNOBSERVABLE here; they are ranked
279	/// with the applications under their rendered head spelling (flagged in
280	/// BEHAVIOR.md, to be confirmed by the corpus gate if they ever occur).
281	fn term_cmp(a: &Term, b: &Term) -> Ordering {
282	    view_cmp(CmpView::Node(a), CmpView::Node(b))
283	}
284	
285	fn view_cmp(a: CmpView, b: CmpView) -> Ordering {
286	    // Resolve single-element tails and tuple nodes to a common shape.
287	    let a = resolve(a);
288	    let b = resolve(b);
289	    match (var_of(a), var_of(b)) {
290	        (Some(va), Some(vb)) => {
291	            va.name.cmp(&vb.name).then(va.idx.cmp(&vb.idx))
292	        }
293	        (Some(_), None) => Ordering::Less,
294	        (None, Some(_)) => Ordering::Greater,
295	        (None, None) => {
296	            let (na, aa) = app_view(a);
297	            let (nb, ab) = app_view(b);
298	            na.cmp(&nb).then_with(|| args_cmp(&aa, &ab))
299	        }
300	    }
301	}
302	
303	/// Collapse a one-element pair tail to its element (a tuple `<a, b, c>` is
304	/// `pair(a, pair(b, c))` — the final tail is just the last element).
305	fn resolve(v: CmpView) -> CmpView {
306	    match v {
307	        CmpView::PairTail(elems) if elems.len() == 1 => {
308	            resolve(CmpView::Node(&elems[0]))
309	        }
310	        CmpView::Node(Term::Pair(elems)) => resolve(CmpView::PairTail(elems)),
311	        other => other,
312	    }
313	}
314	
315	fn var_of<'a>(v: CmpView<'a>) -> Option<&'a VarSpec> {
316	    match v {
317	        CmpView::Node(Term::Var(spec)) => Some(spec),
318	        _ => None,
319	    }
320	}
321	
322	/// Head spelling + argument views of an application-like term.
323	fn app_view(v: CmpView) -> (String, Vec<CmpView>) {
324	    match v {
325	        CmpView::PairTail(elems) => (
326	            "pair".into(),
327	            vec![CmpView::Node(&elems[0]), CmpView::PairTail(&elems[1..])],
328	        ),
329	        CmpView::Node(t) => match t {
330	            Term::App(f, args) => {
331	                (f.clone(), args.iter().map(CmpView::Node).collect())
332	            }
333	            Term::AlgApp(f, x, y) => {
334	                (f.clone(), vec![CmpView::Node(x), CmpView::Node(y)])
335	            }
336	            Term::Diff(l, r) => {
337	                ("diff".into(), vec![CmpView::Node(l), CmpView::Node(r)])
338	            }
339	            // UNOBSERVABLE in equations — rendered-spelling rank (BEHAVIOR.md).
340	            Term::BinOp(op, x, y) => {
341	                let name = match op {
342	                    crate::ast::BinOp::Exp => "^",
343	                    crate::ast::BinOp::Mult => "*",
344	                    crate::ast::BinOp::Union => "++",
345	                    crate::ast::BinOp::Xor => "\u{2295}",
346	                    crate::ast::BinOp::NatPlus => "%+",
347	                };
348	                (name.into(), vec![CmpView::Node(x), CmpView::Node(y)])
349	            }
350	            Term::PatMatch(inner) => ("=".into(), vec![CmpView::Node(inner)]),
351	            other => (crate::term::render(other), Vec::new()),
352	        },
353	    }
354	}
355	
356	fn args_cmp(a: &[CmpView], b: &[CmpView]) -> Ordering {
357	    for (x, y) in a.iter().zip(b.iter()) {
358	        let ord = view_cmp(*x, *y);
359	        if ord != Ordering::Equal {
360	            return ord;
361	        }
362	    }
363	    a.len().cmp(&b.len())
364	}
365	
366	/// `x.<i>` — the variable spelling in builtin-induced equations
367	/// (probe:b_none and every builtin expansion probe).
368	fn xv(i: u64) -> Term {
369	    Term::Var(VarSpec {
370	        name: "x".into(),
371	        idx: i,
372	        sort: SortHint::Untagged,
373	        typ: None,
374	    })
375	}
376	
377	fn app(f: &str, args: Vec<Term>) -> Term {
378	    Term::App(f.into(), args)
379	}
380	
381	fn eq(lhs: Term, rhs: Term) -> Equation {
382	    Equation { lhs, rhs }
383	}
384	
385	/// `fst(<x.1, x.2>) = x.1`, `snd(<x.1, x.2>) = x.2` (probe:b_none).
386	fn base_equations() -> Vec<Equation> {
387	    vec![
388	        eq(app("fst", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(1)),
389	        eq(app("snd", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(2)),
390	    ]
391	}
