395	    match name {
396	        // adec(aenc(x.1, pk(x.2)), x.2) = x.1
397	        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![eq(
398	            app(
399	                "adec",
400	                vec![
401	                    app("aenc", vec![xv(1), app("pk", vec![xv(2)])]),
