403	                ],
404	            ),
405	            xv(1),
406	        )],
407	        // verify(sign(x.1, x.2), x.1, pk(x.2)) = true
408	        "signing" | "dest-signing" => vec![eq(
409	            app(
410	                "verify",
411	                vec![
412	                    app("sign", vec![xv(1), xv(2)]),
413	                    xv(1),
414	                    app("pk", vec![xv(2)]),
415	                ],
416	            ),
417	            app("true", vec![]),
