420	        "symmetric-encryption" | "dest-symmetric-encryption" => vec![eq(
421	            app(
422	                "sdec",
423	                vec![app("senc", vec![xv(1), xv(2)]), xv(2)],
424	            ),
425	            xv(1),
426	        )],
427	        // getMessage(revealSign(x.1, x.2)) = x.1
428	        // revealVerify(revealSign(x.1, x.2), x.1, pk(x.2)) = true
429	        "revealing-signing" => vec![
430	            eq(
431	                app("getMessage", vec![app("revealSign", vec![xv(1), xv(2)])]),
