/// Structural conversion of a parser-AST fact into the clean-AST fact (the two
/// `Fact` / `FactAnnotation` surfaces are identical, per `interface/ast_types.rs`).
pub fn fact(f: &p::Fact) -> c::Fact {
    c::Fact {
        persistent: f.persistent,
        name: f.name.clone(),
        args: f.args.iter().map(term).collect(),
        annotations: f.annotations.iter().map(fact_annotation).collect(),
    }
}

fn fact_annotation(a: &p::FactAnnotation) -> c::FactAnnotation {
    match a {
        p::FactAnnotation::SolveFirst => c::FactAnnotation::SolveFirst,
        p::FactAnnotation::SolveLast => c::FactAnnotation::SolveLast,
        p::FactAnnotation::NoSources => c::FactAnnotation::NoSources,
    }
}

/// Structural conversion of a parser-AST rule attribute into the clean-AST one.
///
/// The `Color` value is normalized to the closed form the clean renderer
/// expects (`#`-stripped and lowercased — the clean crate documents "value as
/// supplied, lowercased upstream"); this is input normalization, not render
/// logic.  `Process` / `External` pass through structurally (the clean renderer
/// drops them from the echo).
pub fn rule_attr(a: &p::RuleAttr) -> c::RuleAttr {
    match a {
        p::RuleAttr::Color(hex) => {
            c::RuleAttr::Color(hex.trim_start_matches('#').to_lowercase())
        }
        p::RuleAttr::NoDerivCheck => c::RuleAttr::NoDerivCheck,
        p::RuleAttr::Role(r) => c::RuleAttr::Role(r.clone()),
        p::RuleAttr::IsSapicRule => c::RuleAttr::IsSapicRule,
        p::RuleAttr::Process(s) => c::RuleAttr::Process(s.clone()),
        p::RuleAttr::External(k, v) => c::RuleAttr::External(k.clone(), v.clone()),
    }
}

