    let open_ac_nonempty = rule_open_ac_nonempty(parsed_rule, elab_rule, auto_sources);
    let show_loop_breakers = !manual_variants || open_ac_nonempty;

    // ── clean-crate render (R2 rule route) ──────────────────────────────────
    // Translate the ported values into the clean AST and hand the whole block
    // to `pretty_clean::render_rule`.  Facts are AC-canonicalised
    // (`canonicalize_ac_in_pfact`) before conversion — the same normalization
    // the ported body renderer applied — so the clean multiset flattening
    // matches HS's sorted order.  The outer (E-rule) loop-breaker line is gated
    // by `show_loop_breakers`; the AC-rule loop-breaker line inside the comment
    // is always shown (matching the ported `render_ac_variants_block`).
    use crate::elaborate::canonicalize_ac_in_pfact;
    use crate::pretty_clean::ast as c;
    let to_clean_facts = |facts: &[p::Fact]| -> Vec<c::Fact> {
        facts
            .iter()
            .map(canonicalize_ac_in_pfact)
            .map(|f| crate::pretty_clean_adapt::fact(&f))
            .collect()
    };
    let attributes: Vec<c::RuleAttr> = parsed_rule
        .attributes
        .iter()
        .map(crate::pretty_clean_adapt::rule_attr)
        .collect();
    let e_loop_breakers: Vec<usize> = if show_loop_breakers {
        elab_rule
            .map(|r| r.loop_breakers.iter().map(|b| b.0).collect())
            .unwrap_or_default()
    } else {
        Vec::new()
    };
    let e_rule = c::Rule {
        name: name.clone(),
        modulo: Some("E".to_string()),
        attributes: attributes.clone(),
        premises: to_clean_facts(&premises),
        actions: to_clean_facts(&actions),
        conclusions: to_clean_facts(&conclusions),
        loop_breakers: e_loop_breakers,
    };
    let variants: Option<c::AcVariants> = if trivial {
        None
    } else {
        elab_rule.map(|r| {
            let ac = r.abstracted_rule.as_ref().unwrap_or(&r.rule);
            let ac_rule = c::Rule {
                name: name.clone(),
                modulo: Some("AC".to_string()),
                attributes: attributes.clone(),
                premises: to_clean_facts(&lnfacts_to_parser(&ac.premises)),
                actions: to_clean_facts(&lnfacts_to_parser(&ac.actions)),
                conclusions: to_clean_facts(&lnfacts_to_parser(&ac.conclusions)),
                loop_breakers: r.loop_breakers.iter().map(|b| b.0).collect(),
            };
            let has_residual = r.variant_substs.iter().any(|s| !s.is_empty());
            let substitutions: Vec<Vec<(c::Term, c::Term)>> = if has_residual {
                r.variant_substs
                    .iter()
                    .map(|subst| {
                        subst
                            .to_list()
                            .iter()
                            .map(|(v, t)| {
                                (
                                    crate::pretty_clean_adapt::term(&lvar_to_parser_term(v)),
                                    crate::pretty_clean_adapt::term(&lnterm_to_parser(t)),
                                )
                            })
                            .collect()
                    })
                    .collect()
            } else {
                Vec::new()
            };
            c::AcVariants { ac_rule, substitutions }
        })
    };
    crate::pretty_clean::render_rule(&e_rule, variants.as_ref())
}

